
'use client';

import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import Layout from '../shared/Layout';
import { Calendar, BookOpen } from 'lucide-react';
import { motion } from 'framer-motion';
import MySubjects from './MySubjects';
import MakeRequest from './MakeRequest';
import MyRequests from './MyRequests';
import MySessions from './MySessions';
import EnrollSubject from './EnrollSubject';
import Library from './Library';

export default function StudentDashboard() {
  const { user } = useAuth();
  const [currentView, setCurrentView] = useState('home');
  const [todayClasses, setTodayClasses] = useState<any[]>([]);

  useEffect(() => {
    if (currentView === 'home') {
      loadTodayClasses();
    }
  }, [currentView, user]);

  const loadTodayClasses = () => {
    if (!user) return;
    const enrollments = JSON.parse(localStorage.getItem('enrollments') || '[]');
    const subjects = JSON.parse(localStorage.getItem('subjects') || '[]');

    const myEnrollments = enrollments.filter(
      (e: any) => e.studentId === user.id && e.status === 'approved'
    );
    const mySubjectIds = myEnrollments.map((e: any) => e.subjectId);
    const mySubjects = subjects.filter((s: any) => mySubjectIds.includes(s.id));
    
    const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
    const today = days[new Date().getDay()];
    const now = new Date();

    const classes = mySubjects.filter(subject => subject.day === today)
    .map(subject => {
        const [startHour, startMin] = subject.startTime.split(':').map(Number);
        const [endHour, endMin] = subject.dismissalTime.split(':').map(Number);
        
        const startTime = new Date();
        startTime.setHours(startHour, startMin, 0, 0);
        
        const endTime = new Date();
        endTime.setHours(endHour, endMin, 0, 0);

        let status = 'upcoming';
        if (now >= startTime && now <= endTime) {
        status = 'ongoing';
        } else if (now > endTime) {
        status = 'ended';
        }

        if (status !== 'ended') {
            return {
                ...subject,
                status
            }
        }
        return null;
    }).filter(Boolean);

    setTodayClasses(classes);
  };

  const renderHome = () => (
    <div>
      <motion.div
        initial={{ y: -20, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        transition={{ duration: 0.5 }}
      >
        <h2 className="text-3xl mb-2">Hello, {user?.name}</h2>
        <p className="text-gray-600 text-lg mb-8">Student Dashboard</p>
      </motion.div>

      <motion.div 
        className="bg-white/80 backdrop-blur-sm rounded-3xl shadow-xl p-8 border border-gray-100"
        initial={{ scale: 0.95, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        transition={{ duration: 0.5, delay: 0.2 }}
      >
        <motion.h3 
          className="text-2xl mb-6 flex items-center gap-2"
          initial={{ x: -20, opacity: 0 }}
          animate={{ x: 0, opacity: 1 }}
          transition={{ delay: 0.3, duration: 0.5 }}
        >
          <Calendar className="text-[#b40000]" />
          Today's Classes
        </motion.h3>

        {todayClasses.length === 0 ? (
          <motion.div 
            className="text-center py-12 text-gray-500"
            initial={{ scale: 0.9, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            transition={{ delay: 0.4, duration: 0.5 }}
          >
            <BookOpen size={64} className="mx-auto mb-4 opacity-50" />
            <p className="text-lg">Wala kang klase ngayon o wala sa oras mo.</p>
          </motion.div>
        ) : (
          <div className="space-y-4">
           {/* Display ongoing classes */}
           {/* Display upcoming classes */}
          </div>
        )}
      </motion.div>
    </div>
  );

  const renderContent = () => {
    switch (currentView) {
      case 'home':
        return renderHome();
      case 'subjects':
        return <MySubjects />;
      case 'make-request':
        return <MakeRequest />;
      case 'my-requests':
        return <MyRequests />;
      case 'my-sessions':
        return <MySessions />;
      case 'enroll':
        return <EnrollSubject />;
      case 'library':
        return <Library />;
      default:
        return renderHome();
    }
  };

  return (
    <Layout currentView={currentView} onNavigate={setCurrentView}>
      {renderContent()}
    </Layout>
  );
}
