
'use client';

import { useState, useEffect } from 'react';
import { getEnrollmentsAction, getUsersAction, getSubjectsAction, updateEnrollmentAction } from '@/app/actions/dbActions';
import { Subject, User, Enrollment } from '@/utils/storage';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { CheckCircle, XCircle, Clock } from 'lucide-react';
import { toast } from 'sonner';

interface PendingEnrollmentsProps {
  teacherId: string;
}

export default function PendingEnrollments({ teacherId }: PendingEnrollmentsProps) {
  const [pendingEnrollments, setPendingEnrollments] = useState<Array<{
    enrollment: Enrollment;
    student: User;
    subject: Subject;
  }>>([]);

  useEffect(() => {
    loadPendingEnrollments();
  }, [teacherId]);

  const loadPendingEnrollments = async () => {
    const enrollments = await getEnrollmentsAction();
    const subjects = await getSubjectsAction();
    const users = await getUsersAction();

    const teacherSubjects = subjects.filter(s => s.teacherId === teacherId);
    const teacherSubjectIds = teacherSubjects.map(s => s.id);

    const pending = enrollments
      .filter(e => e.status === 'pending' && teacherSubjectIds.includes(e.subjectId))
      .map(enrollment => {
        const student = users.find(u => u.id === enrollment.studentId);
        const subject = subjects.find(s => s.id === enrollment.subjectId);
        return { enrollment, student: student!, subject: subject! };
      })
      .filter(item => item.student && item.subject);

    setPendingEnrollments(pending);
  };

  const handleApprove = async (enrollmentId: string, studentName: string, subjectName: string) => {
    await updateEnrollmentAction(enrollmentId, { status: 'approved' });
    toast.success(`Access granted for ${studentName} in ${subjectName}`);
    loadPendingEnrollments();
  };

  const handleReject = async (enrollmentId: string, studentName: string, subjectName: string) => {
    await updateEnrollmentAction(enrollmentId, { status: 'rejected' });
    toast.error(`Request denied for ${studentName} in ${subjectName}`);
    loadPendingEnrollments();
  };

  if (pendingEnrollments.length === 0) {
    return (
      <div className="text-center py-24 bg-muted/20 rounded-[2.5rem] border-4 border-dashed border-primary/10">
        <Clock className="h-16 w-16 text-primary/20 mx-auto mb-4" />
        <p className="text-muted-foreground font-black uppercase tracking-widest text-xs">No pending authorization requests</p>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      <div>
        <h2 className="text-4xl font-black tracking-tighter">Access Requests</h2>
        <p className="text-muted-foreground font-bold uppercase tracking-widest text-[10px] mt-1">Manual Enrollment Verification</p>
      </div>

      <div className="grid gap-8 md:grid-cols-2">
        {pendingEnrollments.map(({ enrollment, student, subject }) => (
          <Card key={enrollment.id} className="border-primary/5 shadow-2xl rounded-[2.5rem] overflow-hidden bg-white hover:border-primary/20 transition-all">
            <div className="h-2 bg-primary w-full" />
            <CardHeader className="p-8 pb-4">
              <CardTitle className="text-2xl font-black tracking-tight">{student.name}</CardTitle>
              <CardDescription className="font-black text-muted-foreground uppercase text-[10px] tracking-widest mt-1">
                {student.program} • Year {student.year}
              </CardDescription>
            </CardHeader>
            <CardContent className="p-8 pt-4 space-y-6">
              <div className="bg-primary/5 p-6 rounded-[1.5rem] border border-primary/10">
                <p className="text-[9px] font-black uppercase text-muted-foreground tracking-widest mb-2">Requested Session</p>
                <p className="font-black text-xl text-primary">{subject.name}</p>
                <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest mt-1">{subject.day} • {subject.startTime}</p>
              </div>
              <div className="flex gap-4">
                <Button
                  onClick={() => handleApprove(enrollment.id, student.name, subject.name)}
                  className="flex-1 bg-primary hover:bg-primary/90 text-white font-black h-14 rounded-2xl shadow-xl shadow-primary/20 uppercase tracking-widest text-xs"
                >
                  <CheckCircle className="w-4 h-4 mr-2" />
                  Grant Access
                </Button>
                <Button
                  onClick={() => handleReject(enrollment.id, student.name, subject.name)}
                  variant="outline"
                  className="flex-1 border-primary/20 hover:bg-primary/5 text-primary font-black h-14 rounded-2xl uppercase tracking-widest text-xs"
                >
                  <XCircle className="w-4 h-4 mr-2" />
                  Deny
                </Button>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>
    </div>
  );
}
